import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"世界観設定","description":"","frontmatter":{},"headers":[],"relativePath":"ja/story/worldbuilding.md","filePath":"ja/story/worldbuilding.md","lastUpdated":1775394001000}'),d={name:"ja/story/worldbuilding.md"};function i(n,t,s,o,h,f){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="世界観設定" tabindex="-1">世界観設定 <a class="header-anchor" href="#世界観設定" aria-label="Permalink to &quot;世界観設定&quot;">​</a></h1><p>忘却前夜（Morimens）の世界観はクトゥルフ神話をベースに独自の設定が組み込まれています。</p><h2 id="基本設定" tabindex="-1">基本設定 <a class="header-anchor" href="#基本設定" aria-label="Permalink to &quot;基本設定&quot;">​</a></h2><p>忘却前夜の世界では、太古より存在する4つの界域の力が人類の歴史に影を落としています。界域の力に「覚醒」した者たちは覚醒体と呼ばれ、迫りくる宇宙的脅威に対抗する使命を負います。</p><h2 id="組織・勢力" tabindex="-1">組織・勢力 <a class="header-anchor" href="#組織・勢力" aria-label="Permalink to &quot;組織・勢力&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="界域と旧支配者" tabindex="-1">界域と旧支配者 <a class="header-anchor" href="#界域と旧支配者" aria-label="Permalink to &quot;界域と旧支配者&quot;">​</a></h2><p>4つの界域はそれぞれ異なる旧支配者・外なる神の影響下にあります。</p><table tabindex="0"><thead><tr><th style="text-align:center;">界域</th><th style="text-align:left;">関連する神話存在</th><th style="text-align:left;">影響</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-chaos">混沌</span></td><td style="text-align:left;">ナイアルラトホテプ、アザトース</td><td style="text-align:left;">狂気・精神汚染</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">クトゥルフ、ダゴン</td><td style="text-align:left;">深海の呼び声・変異</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">シュブ＝ニグラス</td><td style="text-align:left;">肉体変容・増殖</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">ヨグ＝ソトース</td><td style="text-align:left;">次元干渉・時空歪曲</td></tr></tbody></table><h2 id="重要用語" tabindex="-1">重要用語 <a class="header-anchor" href="#重要用語" aria-label="Permalink to &quot;重要用語&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">用語</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;">覚醒体</td><td style="text-align:left;">界域の力に覚醒した人間</td></tr><tr><td style="text-align:left;">忘却前夜</td><td style="text-align:left;">全ての記憶・存在が消滅する「忘却」の前夜</td></tr><tr><td style="text-align:left;">銀鍵</td><td style="text-align:left;">ヨグ＝ソトースの門を開く鍵。ゲーム内では戦闘リソース</td></tr><tr><td style="text-align:left;">算力</td><td style="text-align:left;">覚醒体が界域の力を行使するためのエネルギー</td></tr><tr><td style="text-align:left;">狂気</td><td style="text-align:left;">界域の力を使いすぎることで蓄積する精神的負荷</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">ストーリー概要</a></li><li><a href="./main.html">メインストーリー</a></li><li><a href="./../realms/">界域概要</a></li><li><a href="./silver-core.html">銀芯通信</a></li></ul>',13)])])}const g=e(d,[["render",i]]);export{c as __pageData,g as default};
